import HomeBanner from "../../Components/Header/HomeBanner";
import banner1 from "../../assets/images/banner1.png";
import Button from "@mui/material/Button";
import { IoIosArrowRoundForward } from "react-icons/io";
import React from "react";
import Slider from "react-slick";
// import { FaAngleLeft } from "react-icons/fa";
import sp1 from "../../assets/images/sp1.png";
import sp2 from "../../assets/images/sp2.png";
import sp3 from "../../assets/images/sp3.png";
import sp4 from "../../assets/images/sp4.png";
import sp5 from "../../assets/images/sp5.png";

const Home = () => {
  var settings = {
    dots: true,
    infinite: true,
    speed: 500,
    slidesToShow: 1,
    slidesToScroll: 1,
  };
  return (
    <>
      <HomeBanner />
      <section className="homeProducts">
        <div className="container">
          <div className="row">
            <div className="col-md-3">
              <div className="banner">
                <img src={banner1} className="cursor w-100" alt="Banner" />
              </div>
            </div>
            <div className="col-md-9 productRow">
              <div className="d-flex align-items-center">
                <div className="info w-75">
                  <h3 className="mb-0 hd">SẢN PHẨM BÁN CHẠY</h3>
                  <p className="text-light text-sml mb-0">
                    Đừng bỏ lỡ các ưu đãi hiện tại cho đến cuối tháng 11
                  </p>
                </div>
                <Button className="viewAllButton ml-auto">
                  Xem tất cả <IoIosArrowRoundForward />
                </Button>
              </div>
              <div className="product-row">
                <Slider {...settings}>
                  <div className="item">
                    <img src={sp2} className="bestsale" alt="BestSale" />{" "}
                  </div>
                  <div className="item">
                    {" "}
                    <img src={sp3} className="bestsale" alt="BestSale" />{" "}
                  </div>
                  <div className="item">
                    {" "}
                    <img src={sp4} className="bestsale" alt="BestSale" />{" "}
                  </div>
                  <div className="item">
                    {" "}
                    <img src={sp5} className="bestsale" alt="BestSale" />{" "}
                  </div>
                  <div className="item">
                    {" "}
                    <img src={sp1} className="bestsale" alt="BestSale" />{" "}
                  </div>
                  <div className="item">
                    {" "}
                    <img src={sp1} className="bestsale" alt="BestSale" />{" "}
                  </div>
                </Slider>
              </div>
            </div>
          </div>
        </div>
      </section>
    </>
  );
};

export default Home;
